/*
 * montty.c — COMP 421 Lab 1: MonTTY Terminal Device Driver
 *
 * Mesa-style monitor implementation.
 * All 7 required entry procedures call Declare_Monitor_Entry_Procedure().
 * Internal helpers are declared static.
 * Only one monitor is used for all terminals.
 */

#include <string.h>

#include <threads.h>
#include <hardware.h>
#include <terminals.h>

#ifndef TERMINAL_MAX_LINE
#define TERMINAL_MAX_LINE 1024
#endif

#ifndef ERROR
#define ERROR (-1)
#endif

/*
 * Input buffer: holds all pending input (complete lines + current partial
 * line).  Size is generous to allow several complete lines to queue up.
 */
#define INPUT_BUF_SIZE  4096

/*
 * Echo circular buffer.  Each typed character may produce up to 3 echo
 * bytes (backspace → "\b \b"); newline/CR → "\r\n" (2 bytes).
 * TERMINAL_MAX_LINE * 4 is ample.
 */
#define ECHO_BUF_SIZE   4096

/* Per-terminal state -------------------------------------------------- */
typedef struct {
    int initialized;

    /* Line-oriented input buffer (flat; consumed from front) */
    char  input_buf[INPUT_BUF_SIZE];
    int   input_len;     /* chars currently buffered                   */
    int   line_count;    /* number of '\n' chars in input_buf          */

    /* Echo output circular buffer (priority over WriteTerminal output) */
    char  echo_buf[ECHO_BUF_SIZE];
    int   echo_head;     /* next char to dequeue                       */
    int   echo_tail;     /* next free slot                             */

    /* Active WriteTerminal operation (one writer at a time)           */
    char *write_buf;     /* pointer into caller's buffer               */
    int   write_pos;     /* original chars consumed so far             */
    int   write_len;     /* total original chars to send               */
    int   write_cr;      /* 1 when '\r' was sent; need to send '\n'    */
    int   writer_active; /* 1 while a writer holds the slot            */

    /* Hardware transmitter state */
    int   transmit_busy; /* 1 while a char is being transmitted        */

    /* Condition variables */
    cond_id_t line_ready;  /* ReadTerminal waits here for a full line  */
    cond_id_t write_done;  /* WriteTerminal waits here for tx complete */
    cond_id_t write_avail; /* serialises concurrent WriteTerminal calls*/

    /* Statistics */
    struct termstat stats;
} terminal_t;

/* Global driver state ------------------------------------------------- */
static int        driver_initialized = 0;
static terminal_t terminals[NUM_TERMINALS];

/* ===================================================================== */
/* Internal (static) helper procedures                                   */
/* ===================================================================== */

static int
echo_has_chars(int term)
{
    return terminals[term].echo_head != terminals[term].echo_tail;
}

static void
echo_enqueue(int term, char c)
{
    terminal_t *t    = &terminals[term];
    int         next = (t->echo_tail + 1) % ECHO_BUF_SIZE;
    if (next == t->echo_head)
        return;   /* buffer full; drop silently */
    t->echo_buf[t->echo_tail] = c;
    t->echo_tail = next;
}

static char
echo_dequeue(int term)
{
    terminal_t *t = &terminals[term];
    char        c = t->echo_buf[t->echo_head];
    t->echo_head = (t->echo_head + 1) % ECHO_BUF_SIZE;
    return c;
}

/* Returns 1 if there are write chars still to transmit */
static int
write_has_chars(int term)
{
    terminal_t *t = &terminals[term];
    return t->writer_active &&
           (t->write_cr || t->write_pos < t->write_len);
}

/*
 * Returns the next character to transmit for the active write, applying
 * '\n' → "\r\n" expansion.  Advances write_pos as appropriate.
 */
static char
write_next_char(int term)
{
    terminal_t *t = &terminals[term];
    char        c;

    if (t->write_cr) {
        /* We already sent '\r'; now send '\n' and advance past the '\n' */
        t->write_cr = 0;
        t->write_pos++;
        return '\n';
    }
    c = t->write_buf[t->write_pos];
    if (c == '\n') {
        /* Send '\r' first; next time we will send '\n' */
        t->write_cr = 1;
        return '\r';
    }
    t->write_pos++;
    return c;
}

/*
 * If the transmitter is free, start sending the next character.
 * Echo output has priority over WriteTerminal output.
 */
static void
try_start_transmit(int term)
{
    terminal_t *t = &terminals[term];
    char        c;

    if (t->transmit_busy)
        return;

    if (echo_has_chars(term)) {
        c = echo_dequeue(term);
        WriteDataRegister(term, c);
        t->stats.tty_out++;
        t->transmit_busy = 1;
        return;
    }

    if (write_has_chars(term)) {
        c = write_next_char(term);
        WriteDataRegister(term, c);
        t->stats.tty_out++;
        t->transmit_busy = 1;
        return;
    }
}

/*
 * Returns the number of characters in the current (incomplete) line
 * being typed — i.e., chars after the last '\n' in input_buf.
 */
static int
current_line_len(int term)
{
    terminal_t *t = &terminals[term];
    int         i;

    for (i = t->input_len - 1; i >= 0; i--) {
        if (t->input_buf[i] == '\n')
            return t->input_len - i - 1;
    }
    return t->input_len;
}

/* ===================================================================== */
/* Monitor entry procedures (Section 6)                                  */
/* ===================================================================== */

int
InitTerminalDriver(void)
{
    Declare_Monitor_Entry_Procedure();

    int i;

    if (driver_initialized)
        return ERROR;

    for (i = 0; i < NUM_TERMINALS; i++) {
        terminal_t *t = &terminals[i];

        t->initialized   = 0;
        t->input_len     = 0;
        t->line_count    = 0;
        t->echo_head     = 0;
        t->echo_tail     = 0;
        t->write_buf     = NULL;
        t->write_pos     = 0;
        t->write_len     = 0;
        t->write_cr      = 0;
        t->writer_active = 0;
        t->transmit_busy = 0;

        t->line_ready    = CondCreate();
        t->write_done    = CondCreate();
        t->write_avail   = CondCreate();

        t->stats.tty_in  = -1;
        t->stats.tty_out = -1;
        t->stats.user_in = -1;
        t->stats.user_out = -1;
    }

    driver_initialized = 1;
    return 0;
}

int
InitTerminal(int term)
{
    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized)             return ERROR;
    if (term < 0 || term >= NUM_TERMINALS) return ERROR;
    if (terminals[term].initialized)     return ERROR;
    if (InitHardware(term) == ERROR)     return ERROR;

    terminals[term].initialized  = 1;
    terminals[term].stats.tty_in  = 0;
    terminals[term].stats.tty_out = 0;
    terminals[term].stats.user_in  = 0;
    terminals[term].stats.user_out = 0;

    return 0;
}

int
ReadTerminal(int term, char *buf, int buflen)
{
    Declare_Monitor_Entry_Procedure();

    terminal_t *t;
    int         n;
    char        c;

    if (!driver_initialized)               return ERROR;
    if (term < 0 || term >= NUM_TERMINALS) return ERROR;
    if (!terminals[term].initialized)      return ERROR;
    if (buf == NULL && buflen > 0)         return ERROR;
    if (buflen < 0)                        return ERROR;
    if (buflen == 0)                       return 0;

    t = &terminals[term];

    /* Mesa wait: block until a complete line is available */
    while (t->line_count == 0)
        CondWait(t->line_ready);

    /* Copy chars from front of input_buf, up to buflen or until '\n' */
    n = 0;
    while (n < buflen && t->input_len > 0) {
        c = t->input_buf[0];
        memmove(t->input_buf, t->input_buf + 1, (size_t)(t->input_len - 1));
        t->input_len--;
        buf[n++] = c;
        if (c == '\n') {
            t->line_count--;
            break;
        }
    }

    /*
     * If there is still at least one complete line in the buffer
     * (either because we stopped early due to buflen, or because
     * there were multiple lines), wake the next reader.
     */
    if (t->line_count > 0)
        CondSignal(t->line_ready);

    t->stats.user_out += n;
    return n;
}

int
WriteTerminal(int term, char *buf, int buflen)
{
    Declare_Monitor_Entry_Procedure();

    terminal_t *t;

    if (!driver_initialized)               return ERROR;
    if (term < 0 || term >= NUM_TERMINALS) return ERROR;
    if (!terminals[term].initialized)      return ERROR;
    if (buf == NULL)                       return ERROR;
    if (buflen < 0)                        return ERROR;
    if (buflen == 0)                       return 0;

    t = &terminals[term];

    /* user_in is incremented when WriteTerminal is called */
    t->stats.user_in += buflen;

    /* Serialise: wait until the previous writer is done */
    while (t->writer_active)
        CondWait(t->write_avail);

    /* Claim the writer slot */
    t->writer_active = 1;
    t->write_buf     = buf;
    t->write_pos     = 0;
    t->write_len     = buflen;
    t->write_cr      = 0;

    /* Kick off transmission if the hardware is free */
    try_start_transmit(term);

    /* Mesa wait: block until all chars have been handed to the hardware */
    while (write_has_chars(term))
        CondWait(t->write_done);

    /* Release the writer slot */
    t->writer_active = 0;
    CondSignal(t->write_avail);

    return buflen;
}

int
TerminalDriverStatistics(struct termstat *stats)
{
    Declare_Monitor_Entry_Procedure();

    int i;

    if (!driver_initialized) return ERROR;
    if (stats == NULL)       return ERROR;

    for (i = 0; i < NUM_TERMINALS; i++)
        stats[i] = terminals[i].stats;

    return 0;
}

void
ReceiveInterrupt(int term)
{
    Declare_Monitor_Entry_Procedure();
    /* This handler MUST NOT block (no CondWait). */

    terminal_t *t = &terminals[term];
    char        c = ReadDataRegister(term);

    t->stats.tty_in++;

    if (c == '\r' || c == '\n') {
        /*
         * Carriage-return or newline: echo "\r\n", store '\n'.
         */
        echo_enqueue(term, '\r');
        echo_enqueue(term, '\n');
        if (t->input_len < INPUT_BUF_SIZE) {
            t->input_buf[t->input_len++] = '\n';
            t->line_count++;
            CondSignal(t->line_ready);
        }
    } else if (c == '\b' || c == '\177') {
        /*
         * Backspace / DEL: remove last char from the current line.
         * We must not erase past the last '\n' in the buffer.
         */
        if (current_line_len(term) > 0) {
            t->input_len--;
            echo_enqueue(term, '\b');
            echo_enqueue(term, ' ');
            echo_enqueue(term, '\b');
        }
        /* else: nothing to delete; do nothing */
    } else {
        /*
         * Ordinary character: store if the current line is not full,
         * then echo it.
         */
        if (current_line_len(term) < TERMINAL_MAX_LINE) {
            t->input_buf[t->input_len++] = c;
            echo_enqueue(term, c);
        }
        /* else: line full; drop character (optionally ring bell) */
    }

    /* Start transmitting the echo if the hardware is free */
    try_start_transmit(term);
}

void
TransmitInterrupt(int term)
{
    Declare_Monitor_Entry_Procedure();

    terminal_t *t = &terminals[term];

    /* The previous character has been fully transmitted */
    t->transmit_busy = 0;

    /* Send the next queued character (echo has priority) */
    try_start_transmit(term);

    /*
     * If there is an active writer and all its characters have been
     * dispatched to the hardware, wake it up so it can return.
     */
    if (t->writer_active && !write_has_chars(term))
        CondSignal(t->write_done);
}
